  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.com/lock-state.schema.json",
  "title": "Lock State",
  "type": "object",
  "required": [
    "global_goal",
    "in_scope",
    "out_of_scope",
    "next_locked",
    "todo",
    "unlock",
    "owner"
  ],
  "properties": {
    "global_goal": {"type": "string", "minLength": 1},
    "in_scope": {"type": "array", "items": {"type": "string"}},
    "out_of_scope": {"type": "array", "items": {"type": "string"}},
    "next_locked": {
      "type": "object",
      "required": ["id", "action"],
      "properties": {
        "id": {"type": "string", "pattern": "^NEXT-[0-9]{4}-[0-9]{2}-[0-9]{2}-[0-9]{2}$"},
