      },
      "additionalProperties": false
    },
    "todo": {
      "type": "object",
      "required": ["P0", "P1", "P2"],
      "properties": {
        "P0": {"type": "array", "items": {"type": "string"}},
        "P1": {"type": "array", "items": {"type": "string"}},
        "P2": {"type": "array", "items": {"type": "string"}}
      },
      "additionalProperties": false
    },
    "unlock": {
      "type": "object",
      "required": ["phrases", "two_step_required"],
      "properties": {
        "phrases": {
          "type": "array",
          "items": {"type": "string"},
          "contains": {"const": "确认解锁"},
          "minItems": 2
        },
        "two_step_required": {"type": "boolean"}
      },
      "additionalProperties": false
    },
    "owner": {
      "type": "object",
      "required": ["lock_owner"],
      "properties": {
        "lock_owner": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}
"}

